#include <stdbool.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long first, val; bool allSame=true;
        scanf("%lld",&first);
        long long a[4]; a[0]=first;
        for(int i=1;i<N;i++){
            scanf("%lld",&val);
            if(i<4) a[i]=val;
            if(val!=first) allSame=false;
        }
        if(N==4){
            long long sum1=a[0]+a[1];
            long long sum2=a[2]+a[3];
            printf(sum1!=sum2?"YES\n":"NO\n");
        }else{
            printf(!allSame?"YES\n":"NO\n");
        }
    }
    return 0;
}

