import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        if N == 4:
            out.append('YES' if arr[0] + arr[1] != arr[2] + arr[3] else 'NO')
        else:
            all_same = all(x == arr[0] for x in arr)
            out.append('NO' if all_same else 'YES')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

